options.customCss:
:root {
	--font-family: 'Inter', 'Open Sans', sans-serif;
	--color-background: #F4F7FF;
	--color-card-bg: #ffffff;
	--color-card-border: #dbdfe7;
	--color-focus-border: #6B63AB;
	--color-submit-btn-bg: #00AEEF;
	--color-submit-btn-text: #ffffff;
	--color-header: #4A4E69;
	--color-label: #555555;
	--color-input-text: #333333;
	--color-html-link: #00AEEF;
	--color-required: #6B63AB;
	--border-radius-card: 12px;
	--border-radius-input: 8px;
	--container-width: 500px;
}

footer, .n8n-form-footer, div[class*="footer"] {
	display: none !important;
}

.n8n-form-card::before {
	content: "";
	display: block;
	width: 100%;
	height: 120px;
	background-image: url('YOUR_IMAGE_URL_HERE');
	background-size: contain;
	background-repeat: no-repeat;
	background-position: center;
	margin-bottom: 20px;
}

button[type="submit"] {
	background: linear-gradient(135deg, #6B63AB 0%, #00AEEF 100%) !important;
	border: none !important;
	font-weight: 600 !important;
	transition: opacity 0.2s;
}

button[type="submit"]:hover {
	opacity: 0.9;
}
